import type React from 'react';
import { useState, useRef, Fragment } from 'react';
import { Breadcrumb, Button, message, Modal, Tooltip, Typography } from 'antd';
import { PageContainer } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { ModalForm, ProFormTextArea } from '@ant-design/pro-form';
import { connectAudits, requestDisconnectConn, updateAudit } from '@/services/api';
import type { API } from '@/services/typings';
import { t, renderDetails, csvFormat, SaveCsv, getTablePaginationConfig } from '../../../global';
import { useIntl, useModel } from '@umijs/max';

import { CameraOutlined, CodeOutlined, EditTwoTone, FileSyncOutlined, FundProjectionScreenOutlined, QuestionOutlined, RetweetOutlined } from '@ant-design/icons';
import { hasPermAuditsEdit, hasPermAuditsEditItem } from '../../RoleList/permissionUtils';

const handleUpdate = async (fields: API.ConnAuditListItem, old: API.ConnAuditListItem) => {
  const data = { guid: old.guid } as any;
  if ((fields.note || '') != (old.note || '')) {
    data['note'] = fields.note;
  }
  if (Object.keys(data).length == 1) return;
  const hide = message.loading(t('Updating'));
  try {
    await updateAudit({ data });
    hide();

    message.success(t('Update is successful'));
    return true;
  } catch (error) {
    hide();
    message.error(
      typeof error == 'string' ? (error as string) : t('Update failed, please try again!'),
    );
    return false;
  }
};

const updateForm = (
  visible: boolean,
  handleModalVisible: React.Dispatch<React.SetStateAction<boolean>>,
  actionRef: React.MutableRefObject<ActionType | undefined>,
  initialValues: API.ConnAuditListItem | {},
) => {
  if (!visible) return null;
  return (
    <ModalForm
      title={t('Edit')}
      visible={visible}
      width="400px"
      initialValues={initialValues}
      onVisibleChange={handleModalVisible}
      onFinish={async (value) => {
        const success = await handleUpdate(
          value as API.ConnAuditListItem,
          initialValues as API.ConnAuditListItem,
        );
        if (success) {
          handleModalVisible(false);
          if (actionRef.current) {
            actionRef.current.reload();
          }
        }
      }}
    >
      <ProFormTextArea
        fieldProps={{ autoComplete: 'off' }}
        width="md"
        name="note"
        rules={[
          {
            max: 300,
          },
        ]}
        label={t('Note', true)}
      />
    </ModalForm>
  );
};

const renderLocal = (record: API.ConnAuditListItem) => {
  let txt = record.local || '';
  let info = {} as any;
  try {
    info = JSON.parse(record.info || '{}');
    if (!txt) txt = info['local'] || '';
    let name = info['name'] || '';
    if (txt.indexOf(name) == -1) txt += ' ' + name;
    let ip = (info['ip'] || '').replace("::ffff:", "");
    if (ip) txt += '@' + ip;
  } catch (e) { }
  return txt;
};


const renderDuration = (record: API.ConnAuditListItem) => {
  if (record.end_time && record.created_at && record.end_time >= record.created_at) {
    const duration = record.end_time - record.created_at;

    const days = Math.floor(duration / (24 * 3600));
    const hours = Math.floor((duration % (24 * 3600)) / 3600);
    const minutes = Math.floor((duration % 3600) / 60);
    const seconds = Math.floor(duration % 60);

    const parts = [];
    if (days > 0) parts.push(`${days}d`);
    if (hours > 0) parts.push(`${hours}h`);
    if (minutes > 0) parts.push(`${minutes}m`);
    if (seconds > 0 || parts.length === 0) parts.push(`${seconds}s`);

    return parts.join(' ');
  }
  return '-';
};

const AuditList: React.FC = () => {
  const [updateModalVisible, handleUpdateModalVisible] = useState<boolean>(false);
  const [showDetail, setShowDetail] = useState<boolean>(false);
  const [disconnectDialogConfirmLoading, setDisconnectDialogConfirmLoading] = useState(false);
  const [disconnectDialogOpen, setDisconnectDialogOpen] = useState(false);
  const [currentDisconnectGuid, setCurrentDisconnectGuid] = useState<String>('');
  const [pageParams, setPageParams] = useState<Partial<API.PageParams>>();
  const [messageApi, contextHolder] = message.useMessage();
  const intl = useIntl();

  const actionRef = useRef<ActionType>();
  const [currentRow, setCurrentRow] = useState<API.ConnAuditListItem>();
  const { initialState } = useModel('@@initialState');
  const canEditAudit = hasPermAuditsEdit(initialState?.user);

  const disconnect_succ_msg = () => {
    messageApi.open({
      type: 'success',
      content: t(
        'pages.AuditList.ConnAuditList.disconnect_succ',
        false,
        'Successfully disconnected!',
      ),
    });
  };

  const disconnect_fail_msg = () => {
    messageApi.open({
      type: 'error',
      content: t('pages.AuditList.ConnAuditList.disconnect_fail', false, 'Disconnect failed!'),
    });
  };

  const doDisconnect = async () => {
    setDisconnectDialogConfirmLoading(true);
    try {
      let res = await requestDisconnectConn(currentDisconnectGuid);
      if (res.succ) {
        disconnect_succ_msg();
        setTimeout(() => actionRef.current?.reload(), 1000);
      } else {
        disconnect_fail_msg();
      }
    } catch (error) {
      message.error(typeof error == 'string' ? (error as string) : 'Disconnect failed!');
    } finally {
      setDisconnectDialogConfirmLoading(false);
      setDisconnectDialogOpen(false);
    }
  };

  const showModal = (guid: string) => {
    setCurrentDisconnectGuid(guid);
    setDisconnectDialogOpen(true);
  };

  const plain = (text: string, defaultMessage = '') => t(text, true, defaultMessage || text, intl) as string;

  const exportCsv = async () => {
    let allItems: API.ConnAuditListItem[] = [];
    let total = 0;
    const pageSize = 100;
    let current = 0;
    do {
      current++;
      const items = await connectAudits({ ...pageParams, current: current, pageSize: pageSize });
      if (total == 0 && items.total != null) {
        total = items.total;
      }
      if (items.data != null) {
        allItems = allItems.concat(items.data);
      }
    } while (current < 10 && pageSize * current < total);

    const titles = ['Type', 'Remote', 'Local', 'Start Time', 'End Time', 'Duration', 'Note'];
    titles.forEach((s, index) => (titles[index] = plain(s)));
    const rows: string[][] = [];
    allItems.forEach((record) => {
      const row: string[] = [];
      let conn_type;
      switch (record.conn_type) {
        case 0:
          conn_type = plain('Normal');
          break;
        case 1:
          conn_type = plain('File Transfer');
          break;
        case 2:
          conn_type = plain('Port Transfer');
          break;
        case 3:
          conn_type = plain('View Camera');
          break;
        case 4:
          conn_type = plain('Terminal');
          break;
        default:
          conn_type = '-';
          break;
      }
      row.push(conn_type);
      row.push(record.remote);
      row.push(renderLocal(record));
      row.push(csvFormat(new Date((record.created_at || 0) * 1000).toLocaleString()));
      row.push(record.end_time ? csvFormat(new Date(record.end_time * 1000).toLocaleString()) : '-');
      row.push(csvFormat(renderDuration(record)));
      row.push(csvFormat(record.note ?? ''));
      rows.push(row);
    });
    SaveCsv(titles, rows, plain('pages.AuditList.ConnAuditList.exportFilename', 'ConnectionAudit'));
  };

  const columns: ProColumns<API.ConnAuditListItem>[] = [
    {
      title: t('ID'),
      dataIndex: 'remote',
      hideInDescriptions: true,
      hideInTable: true,
      tip: t('Remote device', true) as string,
    },
    {
      title: t('Name'),
      dataIndex: 'remote_device_name',
      hideInDescriptions: true,
      hideInTable: true,
      tip: t('Remote device', true) as string,
    },
    {
      title: t('Type'),
      dataIndex: 'conn_type',
      width: 60,
      valueEnum: {
        0: {
          text: t('Remote Desktop'),
        },
        1: {
          text: t('File Transfer'),
        },
        2: {
          text: t('Port Transfer'),
        },
        3: {
          text: t('View Camera'),
        },
        4: {
          text: t('Terminal'),
        },
        undefined: {
          text: t('Not Logged In'),
        },
      },
      render: (dom, entity) => {
        let res;
        switch (entity.conn_type) {
          case 0:
            res = ['Remote Desktop', <FundProjectionScreenOutlined />];
            break;
          case 1:
            res = [t('File Transfer'), <FileSyncOutlined />];
            break;
          case 2:
            res = [t('Port Transfer'), <RetweetOutlined />];
            break;
          case 3:
            res = [t('View Camera'), <CameraOutlined />];
            break;
          case 4:
            res = [t('Terminal'), <CodeOutlined />];
            break;
          default:
            res = ['Not Logged In', <QuestionOutlined />];
            break;
        }
        return (
          <a
            onClick={() => {
              setCurrentRow(entity);
              setShowDetail(true);
            }}
          > <Tooltip title={t(res[0] as string)}>
              {res[1]}
            </Tooltip></a>
        );
      },
    },
    {
      title: t('Remote'),
      dataIndex: 'remote',
      hideInSearch: true,
      tip: t('remoteTip', true, 'Remotely controlled computer or terminal') as string,
    },
    {
      title: t('Local'),
      dataIndex: 'local',
      search: false,
      width: 200,
      render: (text, record) => {
        return renderLocal(record);
      },
    },
    {
      title: t('Start Time'),
      dataIndex: 'created_at',
      valueType: 'dateTime',
      render: (text, record) => new Date((record.created_at || 0) * 1000).toLocaleString(),
    },
    {
      title: t('End Time'),
      dataIndex: 'end_time',
      search: false,
      render: (text, record) =>
        record.end_time ? new Date(record.end_time * 1000).toLocaleString() : '-',
    },
    {
      title: t('Duration'),
      search: false,
      render: (text, record) => {
        return renderDuration(record);
      },
    },
    {
      title: t('Note'),
      dataIndex: 'note',
      valueType: 'textarea',
      search: false,
      width: 200,
      ellipsis: true,
      render: (text, record) => (
        <Fragment>
          <Typography.Text ellipsis={true} style={{ maxWidth: 150 }}>
            <Tooltip title={record.note ? record.note : ''}>
              {record.note ? record.note : ''}
            </Tooltip>
          </Typography.Text>
          {(
            <Button
              style={{ float: 'right' }}
              icon={<EditTwoTone />}
              type="text"
              onClick={() => {
                setCurrentRow(record);
                handleUpdateModalVisible(true);
              }}
            ></Button>
          )}
        </Fragment>
      ),
    },
    {
      title: t('Action'),
      search: false,
      hideInTable: !canEditAudit,
      width: 120,
      render: (text, record) => {
        // Check if current user can edit this specific item
        const canEditItem = hasPermAuditsEditItem(initialState?.user, record);

        if (!canEditItem) {
          return <span style={{ color: '#999' }}>-</span>;
        }

        if (!record.running) {
          return '';
        } else {
          return (
            <Button size="small" type="default" danger onClick={() => showModal(record.guid)}>
              {t('Disconnect')}
            </Button>
          );
        }
      },
    },
  ];

  return (
    (<PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.list.audit-list', true) },
          { title: t('menu.list.audit-list.Connection', true) },
        ]} />
      )}
    >
      <ProTable<API.ConnAuditListItem, API.PageParams>
        headerTitle={t('Log List')}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'connlist_columns_state' }}
        actionRef={actionRef}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        request={connectAudits}
        columns={columns}
        toolBarRender={() => [
          <Tooltip title={t('exportCsvTip', true, 'Export up to 1000 records at a time')}>
            <Button type="default" onClick={exportCsv}>
              {t('Export as csv')}
            </Button>
          </Tooltip>,
        ]}
        beforeSearchSubmit={(params) => {
          setPageParams(params);
          return params;
        }}
        pagination={getTablePaginationConfig("conn_audit_list")}
      />
      {renderDetails(
        showDetail,
        currentRow?.guid,
        currentRow,
        columns.slice(0, columns.length - 1),
        setCurrentRow,
        setShowDetail,
      )}
      {updateForm(updateModalVisible, handleUpdateModalVisible, actionRef, currentRow || {})}
      {disconnectDialogOpen && <Modal
        title={t('pages.AuditList.ConnAuditList.modal_title', true, 'Confirm operation')}
        open={disconnectDialogOpen}
        onOk={doDisconnect}
        onCancel={() => setDisconnectDialogOpen(false)}
        confirmLoading={disconnectDialogConfirmLoading}
      >
        <p>
          {t(
            'pages.AuditList.ConnAuditList.diconnect_confirm_tip',
            true,
            'Are you sure you want to disconnect this device?',
          )}
        </p>
      </Modal>}
      {contextHolder}
    </PageContainer>)
  );
};

export default AuditList;
